 16→function getSafeExternalUrl(value: string) {
 17→  try {
 18→    const url = new URL(value);
 19→
 20→    if (url.protocol === "http:" || url.protocol === "https:") {
 21→      return url.toString();
 22→    }
 23→
 24→    return null;
 25→  } catch {
 26→    return null;
 27→  }
 28→}
 29→
 30→function formatSourceLabel(url: string) {
 31→  try {
 32→    const parsed = new URL(url);
 33→    const value =
 34→      `${parsed.hostname.replace(/^www\./, "")}${parsed.pathname}`.replace(
 35→        /\/$/,
 36→        "",
 37→      );
 38→    return value.length > 46 ? `${value.slice(0, 43)}...` : value;
 39→  } catch {
 40→    return url.length > 46 ? `${url.slice(0, 43)}...` : url;
 41→  }
 42→}
 43→
 44→function formatElapsed(ms: number) {
 45→  if (!Number.isFinite(ms) || ms < 0) {
 46→    return "00:00";
 47→  }
 48→
 49→  const totalSeconds = Math.floor(ms / 1000);
 50→  const seconds = totalSeconds % 60;
 51→  const minutes = Math.floor(totalSeconds / 60) % 60;
 52→  const hours = Math.floor(totalSeconds / 3600);
 53→
 54→  if (hours > 0) {
 55→    return `${hours}:${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")}`;
 56→  }
 57→
 58→  return `${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")}`;
 59→}
 60→
 61→function getActiveStage(job: ImportJob) {
 62→  if (job.status === "queued") {
 63→    return getImportStageEntry("queued");
 64→  }
 65→
 66→  if (job.status === "completed") {
 67→    return getImportStageEntry("done");
 68→  }
 69→
 70→  return getImportStageEntry(job.currentStage);
 71→}
