 73→export function HomePage() {
 74→  const [searchParams, setSearchParams] = useSearchParams();
 75→  const activeImportId = searchParams.get("import");
 76→  const queryClient = useQueryClient();
 77→
 78→  const [url, setUrl] = useState("");
 79→  const [hasEditedUrl, setHasEditedUrl] = useState(false);
 80→  const [view, setView] = useState<ViewMode>("reader");
 81→  const [now, setNow] = useState(() => Date.now());
 82→
 83→  const { data: allJobs = [] } = useQuery(
 84→    orpc.imports.list.queryOptions({ input: {} }),
 85→  );
 86→
 87→  const recentJobs = allJobs
 88→    .slice()
 89→    .sort((a, b) => Date.parse(b.updatedAt) - Date.parse(a.updatedAt))
 90→    .slice(0, 2);
 91→
 92→  const { data: job, error: jobError } = useQuery({
 93→    ...orpc.imports.get.queryOptions({ input: { id: activeImportId ?? "" } }),
 94→    enabled: Boolean(activeImportId),
 95→    refetchInterval: (query) => {
 96→      const status = query.state.data?.status;
 97→      if (status === "completed" || status === "failed") return false;
 98→      return 1200;
 99→    },
100→  });
101→
102→  const createImport = useMutation(
103→    orpc.imports.create.mutationOptions({
104→      onSuccess: (nextJob) => {
105→        queryClient.invalidateQueries({ queryKey: orpc.imports.key() });
106→        setHasEditedUrl(false);
107→        startTransition(() => setActiveImport(nextJob.id));
108→      },
109→    }),
110→  );
111→
112→  useEffect(() => {
113→    setView("reader");
114→  }, []);
115→
116→  useEffect(() => {
117→    if (!job) {
118→      return;
119→    }
120→
121→    if (!hasEditedUrl) {
122→      setUrl(job.sourceUrl);
123→    }
124→  }, [hasEditedUrl, job]);
125→
126→  useEffect(() => {
127→    setNow(Date.now());
128→
129→    if (!job || job.status === "completed" || job.status === "failed") {
130→      return;
131→    }
132→
133→    const intervalId = window.setInterval(() => {
134→      setNow(Date.now());
135→    }, 1000);
136→
137→    return () => {
138→      window.clearInterval(intervalId);
139→    };
140→  }, [job]);
141→
142→  function setActiveImport(importId: string | null) {
143→    const nextSearchParams = new URLSearchParams(searchParams);
144→
145→    if (importId) {
146→      nextSearchParams.set("import", importId);
147→    } else {
148→      nextSearchParams.delete("import");
149→    }
150→
151→    setSearchParams(nextSearchParams);
152→  }
153→
154→  function handleSubmit(event: FormEvent<HTMLFormElement>) {
155→    event.preventDefault();
156→    createImport.mutate({ url, mode: "archive" });
157→  }
158→
159→  function handleSelectJob(selectedJob: ImportJob) {
160→    setHasEditedUrl(false);
161→    setUrl(selectedJob.sourceUrl);
162→    startTransition(() => {
163→      setActiveImport(selectedJob.id);
164→    });
165→  }
166→
167→  const activeStage = job ? getActiveStage(job) : null;
168→  const activeSourceUrl = getSafeExternalUrl(job?.sourceUrl ?? url);
169→  const createdAtMs = job ? Date.parse(job.createdAt) : Number.NaN;
170→  const elapsedTime = formatElapsed(now - createdAtMs);
171→  const showRecentJobs = !activeImportId && recentJobs.length > 0;
172→  const showInlineOriginalButton = Boolean(job && activeSourceUrl);
173→
174→  return (
175→    <div className="mx-auto w-full max-w-5xl">
176→      <Card className="border-border/90 bg-card/92 shadow-panel">
177→        <CardContent className="p-4 sm:p-6">
178→          <div className="space-y-6">
179→            <form className="space-y-3" onSubmit={handleSubmit}>
180→              <div className="flex flex-col gap-3 lg:flex-row lg:items-center">
181→                <div className="relative flex-1">
182→                  <Input
183→                    aria-label="Freigabelink"
184→                    className={cn(
185→                      "h-12 pr-4 text-base",
186→                      showInlineOriginalButton ? "pr-24 sm:pr-40" : null,
187→                    )}
188→                    inputMode="url"
189→                    placeholder="https://chatgpt.com/share/... oder ein anderer öffentlicher KI-Share-Link"
190→                    value={url}
191→                    onChange={(event) => {
192→                      setHasEditedUrl(true);
193→                      setUrl(event.target.value);
194→                    }}
195→                  />
196→
197→                  {showInlineOriginalButton ? (
198→                    <a
199→                      className="absolute right-2 top-1/2 inline-flex h-8 -translate-y-1/2 items-center gap-1 rounded-lg border border-border bg-background/95 px-3 text-xs font-medium text-foreground transition hover:bg-foreground/5"
200→                      href={activeSourceUrl ?? undefined}
201→                      rel="noreferrer"
202→                      target="_blank"
203→                    >
204→                      <span className="sm:hidden">Öffnen</span>
205→                      <span className="hidden sm:inline">Original öffnen</span>
206→                      <ExternalLink className="h-3.5 w-3.5" />
207→                    </a>
208→                  ) : null}
209→                </div>
210→
211→                <Button
212→                  className="h-12 px-5 lg:min-w-[8rem]"
213→                  disabled={createImport.isPending}
214→                  type="submit"
215→                >
216→                  {createImport.isPending ? "Import läuft..." : "Importieren"}
217→                </Button>
218→              </div>
219→
220→              {createImport.error ? (
221→                <div className="rounded-2xl border border-red-300/40 bg-red-100/60 px-4 py-3 text-sm text-red-900">
222→                  {createImport.error.message}
223→                </div>
224→              ) : null}
225→            </form>
226→
227→            {showRecentJobs ? (
228→              <section className="space-y-3">
229→                <div className="flex items-center justify-between">
230→                  <p className="text-[11px] uppercase tracking-[0.2em] text-muted-foreground">
231→                    Letzte Importe
232→                  </p>
233→                  {allJobs.length > 2 ? (
234→                    <Link
235→                      className="text-xs text-muted-foreground transition hover:text-foreground"
236→                      to="/history"
237→                    >
238→                      Alle anzeigen →
239→                    </Link>
240→                  ) : null}
241→                </div>
242→                <div className="flex flex-wrap gap-2">
243→                  {recentJobs.map((recentJob) => (
244→                    <button
245→                      key={recentJob.id}
246→                      className={cn(
247→                        "inline-flex max-w-full items-center rounded-full border px-4 py-2 text-sm transition",
248→                        activeImportId === recentJob.id
249→                          ? "border-primary/30 bg-primary/10 text-primary"
250→                          : "border-border/80 bg-background/65 text-foreground hover:bg-foreground/5",
251→                      )}
252→                      type="button"
253→                      onClick={() => handleSelectJob(recentJob)}
254→                    >
255→                      <span className="max-w-[22rem] truncate">
256→                        {formatSourceLabel(recentJob.sourceUrl)}
257→                      </span>
258→                    </button>
259→                  ))}
260→                </div>
261→              </section>
262→            ) : null}
263→
264→            {jobError ? (
265→              <div className="rounded-2xl border border-red-300/40 bg-red-100/60 px-4 py-3 text-sm text-red-900">
266→                {jobError.message}
267→              </div>
268→            ) : job ? (
269→              <FormatWorkspace
270→                activeStage={activeStage}
271→                elapsedTime={elapsedTime}
272→                job={job}
273→                view={view}
274→                onViewChange={setView}
275→              />
276→            ) : null}
277→          </div>
278→        </CardContent>
279→      </Card>
280→    </div>
281→  );
282→}
